import { Link } from "react-router-dom";

export default function AuthNavbar(props) {
  const [navbarOpen, setNavbarOpen] = React.useState(false);
  const [sidebarOpen, setSidebarOpen] = React.useState(false);
  const [showLogoutConfirm, setShowLogoutConfirm] = React.useState(false);
  
  // ==================== STATE لعروض العمل ====================
  const [showJobOffers, setShowJobOffers] = React.useState(false);
  const [showNotification, setShowNotification] = React.useState(false);
  const [notificationMessage, setNotificationMessage] = React.useState("");
  
  // ==================== بيانات عروض العمل ====================
  const [jobOffers, setJobOffers] = React.useState([
    {
      id: 1,
      restaurantName: "Le Gourmet Parisien",
      location: "Paris 8ème, France",
      position: "Serveur/Serveuse",
      salary: "28000 DA/mois",
      description: "Restaurant gastronomique cherche serveur expérimenté",
      icon: "🍽️",
      status: "pending"
    },
    {
      id: 2,
      restaurantName: "Café de la Paix",
      location: "Lyon Centre, France",
      position: "Barman/Barmaid",
      salary: "25000 DA/mois",
      description: "Café branché cherche barman créatif",
      icon: "🍸",
      status: "pending"
    },
    {
      id: 3,
      restaurantName: "Sushi Master",
      location: "Marseille, France",
      position: "Serveur polyvalent",
      salary: "26000 DA/mois",
      description: "Restaurant japonais cherche serveur dynamique",
      icon: "🍣",
      status: "pending"
    }
  ]);

  // ==================== Paramètres du profil (pour le sidebar) ====================
  const [tempProfile, setTempProfile] = React.useState({
    name: "Ahmed Benali",
    lastName: "Benali",
    role: "Directeur Général",
    location: "Alger, Algérie",
    phone: "+213 5 55 55 55 55",
    workTime: "Lundi - Vendredi: 09:00 - 18:00",
    bio: "Directeur de restaurant passionné avec plus de 10 ans d'expérience dans la gestion d'établissements gastronomiques.",
    coverImage: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
    profileImage: "https://randomuser.me/api/portraits/men/32.jpg"
  });

  // ==================== Liens sociaux ====================
  const [socialLinks, setSocialLinks] = React.useState({
    facebook: "",
    instagram: "",
    twitter: "",
    linkedin: "",
    tiktok: ""
  });

  // ==================== Fonctions ====================
  const handleLogout = () => {
    setShowLogoutConfirm(false);
    alert("👋 Vous êtes déconnecté");
  };

  const saveProfileSettings = () => {
    alert("✅ Profil mis à jour avec succès!");
    setSidebarOpen(false);
  };

  const updateSocialLink = (platform, url) => {
    setSocialLinks({ ...socialLinks, [platform]: url });
  };

  const saveSocialLinks = () => {
    alert("✅ Liens sociaux mis à jour!");
    setSidebarOpen(false);
  };

  // ==================== Fonctions pour les offres d'emploi ====================
  const showNotificationMessage = (message) => {
    setNotificationMessage(message);
    setShowNotification(true);
    setTimeout(() => setShowNotification(false), 3000);
  };

  const handleAcceptOffer = (offerId) => {
    setJobOffers(prev => prev.filter(offer => offer.id !== offerId));
    showNotificationMessage("✅ Félicitations ! Vous avez accepté l'offre. Le restaurant vous contactera bientôt.");
    setShowJobOffers(false);
  };

  const handleRejectOffer = (offerId) => {
    setJobOffers(prev => prev.filter(offer => offer.id !== offerId));
    showNotificationMessage("❌ Vous avez refusé l'offre. D'autres opportunités vous attendent !");
  };

  const pendingOffersCount = jobOffers.length;

  const SocialIcons = () => (
    <div className="flex justify-center gap-4 mt-4">
      {socialLinks.facebook && <a href={socialLinks.facebook} target="_blank" rel="noopener noreferrer" className="text-blue-500 hover:text-blue-400 transition-all duration-300 transform hover:scale-110"><i className="fab fa-facebook-f text-xl"></i></a>}
      {socialLinks.instagram && <a href={socialLinks.instagram} target="_blank" rel="noopener noreferrer" className="text-pink-500 hover:text-pink-400 transition-all duration-300 transform hover:scale-110"><i className="fab fa-instagram text-xl"></i></a>}
      {socialLinks.twitter && <a href={socialLinks.twitter} target="_blank" rel="noopener noreferrer" className="text-blue-400 hover:text-blue-300 transition-all duration-300 transform hover:scale-110"><i className="fab fa-twitter text-xl"></i></a>}
      {socialLinks.linkedin && <a href={socialLinks.linkedin} target="_blank" rel="noopener noreferrer" className="text-blue-700 hover:text-blue-600 transition-all duration-300 transform hover:scale-110"><i className="fab fa-linkedin-in text-xl"></i></a>}
      {socialLinks.tiktok && <a href={socialLinks.tiktok} target="_blank" rel="noopener noreferrer" className="text-white hover:text-gray-300 transition-all duration-300 transform hover:scale-110"><i className="fab fa-tiktok text-xl"></i></a>}
    </div>
  );

  return (
    <>
      <style>
        {`
          .navbar-custom {
            background: linear-gradient(135deg, #9b2dff, #7c3aed, #a855f7);
            box-shadow: 0 4px 20px rgba(139, 92, 246, 0.3);
          }
          
          .navbar-custom .nav-link {
            transition: all 0.3s ease;
          }
          
          .navbar-custom .nav-link:hover {
            color: #e9d5ff !important;
            transform: translateY(-2px);
          }
          
          .mobile-menu {
            background: linear-gradient(135deg, #9b2dff, #7c3aed);
          }

          .settings-icon-btn {
            background: rgba(255,255,255,0.15);
            border: 1px solid rgba(255,255,255,0.4);
            border-radius: 8px;
            width: 36px;
            height: 36px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.3s ease;
            margin-right: 12px;
          }
          
          .settings-icon-btn i {
            font-size: 1rem;
          }
          
          .settings-icon-btn:hover {
            background: rgba(255,255,255,0.3);
            transform: scale(1.05) rotate(15deg);
            box-shadow: 0 0 12px rgba(255,255,255,0.3);
          }
          
          /* Sidebar styles */
          @keyframes slideIn {
            from { transform: translateX(-100%); }
            to { transform: translateX(0); }
          }
          
          @keyframes fadeIn {
            from { opacity: 0; }
            to { opacity: 1; }
          }
          
          .sidebar-overlay {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0,0,0,0.7);
            backdrop-filter: blur(5px);
            z-index: 1000;
            animation: fadeIn 0.3s ease;
          }
          
          .sidebar-manager {
            position: fixed;
            top: 0;
            left: 0;
            width: 85%;
            max-width: 400px;
            height: 100vh;
            background: linear-gradient(135deg, #1a1a2e, #16213e);
            z-index: 1001;
            padding: 20px;
            overflow-y: auto;
            animation: slideIn 0.3s ease;
            border-right: 2px solid #a855f7;
            box-shadow: 5px 0 30px rgba(0,0,0,0.5);
          }
          
          .sidebar-manager::-webkit-scrollbar {
            width: 6px;
          }
          
          .sidebar-manager::-webkit-scrollbar-track {
            background: rgba(255,255,255,0.1);
          }
          
          .sidebar-manager::-webkit-scrollbar-thumb {
            background: #a855f7;
            border-radius: 10px;
          }
          
          .profile-image-sidebar {
            width: 80px;
            height: 80px;
            border-radius: 50%;
            margin: 0 auto;
            border: 3px solid #a855f7;
            object-fit: cover;
          }
          
          .profile-name-sidebar {
            color: white;
            font-size: 1.2rem;
            font-weight: bold;
            margin-top: 10px;
          }
          
          .profile-role-sidebar {
            color: #a855f7;
            font-size: 0.85rem;
            margin-top: 5px;
          }
          
          .sidebar-section {
            margin-bottom: 25px;
            padding-bottom: 20px;
            border-bottom: 1px solid rgba(255,255,255,0.1);
          }
          
          .sidebar-title {
            color: #a855f7;
            font-size: 1rem;
            font-weight: bold;
            margin-bottom: 15px;
            display: flex;
            align-items: center;
            gap: 8px;
          }
          
          .sidebar-input {
            width: 100%;
            padding: 10px;
            background: rgba(255,255,255,0.1);
            border: 1px solid rgba(255,255,255,0.2);
            border-radius: 15px;
            color: white;
            margin-bottom: 10px;
          }
          
          .sidebar-input:focus {
            outline: none;
            border-color: #a855f7;
          }
          
          .sidebar-input::placeholder {
            color: rgba(255,255,255,0.4);
          }
          
          .sidebar-label {
            color: rgba(255,255,255,0.7);
            font-size: 0.75rem;
            margin-bottom: 5px;
            display: block;
          }
          
          .btn-sidebar {
            background: linear-gradient(135deg, #7c3aed, #6d28d9);
            border: none;
            padding: 10px;
            border-radius: 25px;
            color: white;
            font-weight: bold;
            cursor: pointer;
            width: 100%;
            margin-top: 10px;
            transition: all 0.2s;
          }
          
          .btn-sidebar:hover {
            background: linear-gradient(135deg, #8b5cf6, #7c3aed);
            transform: scale(1.02);
          }
          
          .btn-danger-sidebar {
            background: linear-gradient(135deg, #ef4444, #b91c1c);
          }
          
          /* Job Offers Card in Sidebar */
          .job-offers-btn-sidebar {
            background: linear-gradient(135deg, #f59e0b, #d97706);
            border: none;
            padding: 12px;
            border-radius: 25px;
            color: white;
            font-weight: bold;
            cursor: pointer;
            width: 100%;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 10px;
            margin-bottom: 15px;
            transition: all 0.2s;
            position: relative;
          }
          
          .job-offers-btn-sidebar:hover {
            transform: scale(1.02);
            box-shadow: 0 4px 15px rgba(245, 158, 11, 0.4);
          }
          
          .offers-badge-sidebar {
            position: absolute;
            top: -8px;
            right: -8px;
            background: #ef4444;
            color: white;
            border-radius: 50%;
            width: 22px;
            height: 22px;
            font-size: 11px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: bold;
          }
          
          /* Job Offers Modal */
          .job-offers-modal-overlay {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0, 0, 0, 0.95);
            backdrop-filter: blur(12px);
            z-index: 2000;
            display: flex;
            align-items: center;
            justify-content: center;
            animation: fadeIn 0.3s ease;
          }
          
          .job-offers-modal-container {
            background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
            border-radius: 30px;
            width: 90%;
            max-width: 500px;
            max-height: 85vh;
            overflow-y: auto;
            padding: 25px;
            border: 2px solid #f59e0b;
            box-shadow: 0 0 40px rgba(245, 158, 11, 0.3);
            animation: slideUp 0.4s ease;
          }
          
          @keyframes slideUp {
            from {
              opacity: 0;
              transform: translateY(30px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }
          
          .close-offers-btn {
            float: right;
            background: none;
            border: none;
            color: white;
            font-size: 24px;
            cursor: pointer;
            transition: all 0.2s;
          }
          
          .close-offers-btn:hover {
            transform: scale(1.1);
            color: #ef4444;
          }
          
          .offers-title {
            color: white;
            font-size: 1.3rem;
            text-align: center;
            margin-bottom: 20px;
          }
          
          .offers-list {
            display: flex;
            flex-direction: column;
            gap: 20px;
          }
          
          /* Restaurant Card - Simple version */
          .restaurant-card {
            background: rgba(255, 255, 255, 0.08);
            border-radius: 20px;
            padding: 18px;
            transition: all 0.2s;
            border-left: 4px solid #f59e0b;
          }
          
          .restaurant-card:hover {
            background: rgba(255, 255, 255, 0.12);
            transform: translateX(5px);
          }
          
          .restaurant-name {
            color: #fbbf24;
            font-size: 1.1rem;
            font-weight: bold;
            margin-bottom: 8px;
            display: flex;
            align-items: center;
            gap: 8px;
          }
          
          .restaurant-detail {
            color: #cbd5e1;
            font-size: 0.8rem;
            margin-bottom: 5px;
            display: flex;
            align-items: center;
            gap: 6px;
          }
          
          .restaurant-description {
            color: #94a3b8;
            font-size: 0.75rem;
            margin: 8px 0;
            line-height: 1.4;
          }
          
          .restaurant-actions {
            display: flex;
            gap: 10px;
            margin-top: 12px;
          }
          
          .accept-btn {
            background: linear-gradient(135deg, #22c55e, #15803d);
            border: none;
            padding: 6px 16px;
            border-radius: 20px;
            color: white;
            font-weight: bold;
            cursor: pointer;
            font-size: 0.8rem;
            flex: 1;
          }
          
          .reject-btn {
            background: linear-gradient(135deg, #ef4444, #b91c1c);
            border: none;
            padding: 6px 16px;
            border-radius: 20px;
            color: white;
            font-weight: bold;
            cursor: pointer;
            font-size: 0.8rem;
            flex: 1;
          }
          
          .accept-btn:hover, .reject-btn:hover {
            transform: scale(1.02);
            filter: brightness(1.05);
          }
          
          .no-offers-message {
            text-align: center;
            padding: 40px;
            color: #94a3b8;
          }
          
          .notification-toast {
            position: fixed;
            bottom: 30px;
            right: 30px;
            background: linear-gradient(135deg, #22c55e, #15803d);
            color: white;
            padding: 12px 24px;
            border-radius: 12px;
            z-index: 10001;
            animation: slideInRight 0.3s ease;
            box-shadow: 0 5px 20px rgba(0, 0, 0, 0.2);
            font-weight: 500;
          }
          
          @keyframes slideInRight {
            from {
              transform: translateX(100%);
              opacity: 0;
            }
            to {
              transform: translateX(0);
              opacity: 1;
            }
          }
          
          .modal-overlay-custom {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0,0,0,0.95);
            backdrop-filter: blur(10px);
            z-index: 1100;
            display: flex;
            align-items: center;
            justify-content: center;
          }
          
          .modal-content-custom {
            background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
            border-radius: 30px;
            padding: 25px;
            max-width: 500px;
            width: 90%;
            border: 2px solid #a855f7;
            animation: fadeIn 0.3s ease;
          }
          
          .confirm-buttons {
            display: flex;
            gap: 15px;
            justify-content: center;
            margin-top: 20px;
          }
        `}
      </style>
    
      {/* ========== NAVBAR ========== */}
      <nav className="top-0 fixed z-50 w-full flex flex-wrap items-center justify-between px-2 py-3 navbar-custom shadow-lg">
        <div className="container px-4 mx-auto flex flex-wrap items-center justify-between">
          <div className="w-full relative flex justify-between lg:w-auto lg:static lg:block lg:justify-start items-center">
            <div className="settings-icon-btn" onClick={() => setSidebarOpen(true)}>
              <i className="fas fa-cog text-white"></i>
            </div>
            
            <Link
              to="/"
              className="text-white text-sm font-bold leading-relaxed inline-block mr-4 py-2 whitespace-nowrap uppercase"
              style={{
                textShadow: "0 0 10px rgba(168, 85, 247, 0.5)",
                letterSpacing: "1px"
              }}
            >
              Notus React
            </Link>
            
            <button
              className="cursor-pointer text-xl leading-none px-3 py-1 border border-solid border-transparent rounded bg-transparent block lg:hidden outline-none focus:outline-none text-white"
              type="button"
              onClick={() => setNavbarOpen(!navbarOpen)}
            >
              <i className="fas fa-bars"></i>
            </button>
          </div>
          
          <div
            className={
              "lg:flex flex-grow items-center lg:bg-opacity-0 lg:shadow-none" +
              (navbarOpen ? " block" : " hidden")
            }
            id="example-navbar-warning"
            style={navbarOpen ? { background: "linear-gradient(135deg, #9b2dff, #7c3aed)" } : {}}
          >
            <ul className="flex flex-col lg:flex-row list-none lg:ml-auto">
              <li className="flex items-center">
                <Link to="/" className="nav-link text-white px-3 py-4 lg:py-2 flex items-center text-xs uppercase font-bold">
                  <span className="inline-block ml-2">🏠 Home</span>
                </Link>
              </li>
              <li className="flex items-center">
                <Link to="/restaurants" className="nav-link text-white px-3 py-4 lg:py-2 flex items-center text-xs uppercase font-bold">
                  <span className="inline-block ml-2">🍽️ Restaurants</span>
                </Link>
              </li>
              <li className="flex items-center">
                <Link to="/profile" className="nav-link text-white px-3 py-4 lg:py-2 flex items-center text-xs uppercase font-bold">
                  <span className="inline-block ml-2">👤 Profile</span>
                </Link>
              </li>
            </ul>
          </div>
        </div>
      </nav>
      
      {/* ========== SIDEBAR (مع عروض العمل) ========== */}
      {sidebarOpen && (
        <>
          <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)}></div>
          <div className="sidebar-manager">
            <button onClick={() => setSidebarOpen(false)} style={{ float: 'right', background: 'none', border: 'none', color: 'white', fontSize: '24px', cursor: 'pointer' }}>✕</button>
            
            {/* ====== معلومات البروفيل ====== */}
            <div className="text-center mb-5">
              <img src={tempProfile.profileImage} alt="profile" className="profile-image-sidebar" />
              <h4 className="profile-name-sidebar">{tempProfile.name} {tempProfile.lastName}</h4>
              <p className="profile-role-sidebar">{tempProfile.role}</p>
            </div>
            
            {/* ====== زر عروض العمل في السايدبار ====== */}
            <button 
              className="job-offers-btn-sidebar"
              onClick={() => setShowJobOffers(true)}
            >
              <span>🎯</span> عروض العمل
              {pendingOffersCount > 0 && (
                <span className="offers-badge-sidebar">{pendingOffersCount}</span>
              )}
            </button>
            
            {/* ====== قسم إعدادات البروفيل ====== */}
            <div className="sidebar-section">
              <div className="sidebar-title"><i className="fas fa-sliders-h"></i> Paramètres du profil</div>
              
              <label className="sidebar-label">🖼️ Image de couverture (URL)</label>
              <input type="text" className="sidebar-input" value={tempProfile.coverImage} onChange={(e) => setTempProfile({...tempProfile, coverImage: e.target.value})} placeholder="https://example.com/cover.jpg" />
              
              <label className="sidebar-label">👤 Image de profil (URL)</label>
              <input type="text" className="sidebar-input" value={tempProfile.profileImage} onChange={(e) => setTempProfile({...tempProfile, profileImage: e.target.value})} placeholder="https://example.com/profile.jpg" />
              
              <label className="sidebar-label">📛 Prénom</label>
              <input type="text" className="sidebar-input" value={tempProfile.name} onChange={(e) => setTempProfile({...tempProfile, name: e.target.value})} placeholder="Prénom" />
              
              <label className="sidebar-label">📛 Nom de famille</label>
              <input type="text" className="sidebar-input" value={tempProfile.lastName} onChange={(e) => setTempProfile({...tempProfile, lastName: e.target.value})} placeholder="Nom de famille" />
              
              <label className="sidebar-label">💼 Poste / Rôle</label>
              <input type="text" className="sidebar-input" value={tempProfile.role} onChange={(e) => setTempProfile({...tempProfile, role: e.target.value})} placeholder="Directeur Général" />
              
              <label className="sidebar-label">📍 Ville / Localisation</label>
              <input type="text" className="sidebar-input" value={tempProfile.location} onChange={(e) => setTempProfile({...tempProfile, location: e.target.value})} placeholder="Ville" />
              
              <label className="sidebar-label">📞 Téléphone</label>
              <input type="tel" className="sidebar-input" value={tempProfile.phone} onChange={(e) => setTempProfile({...tempProfile, phone: e.target.value})} placeholder="Téléphone" />
              
              <label className="sidebar-label">⏰ Horaires de travail</label>
              <input type="text" className="sidebar-input" value={tempProfile.workTime} onChange={(e) => setTempProfile({...tempProfile, workTime: e.target.value})} placeholder="Lundi - Vendredi: 09:00 - 18:00" />
              
              <label className="sidebar-label">📝 Bio / Description</label>
              <textarea className="sidebar-input" rows="3" value={tempProfile.bio} onChange={(e) => setTempProfile({...tempProfile, bio: e.target.value})} placeholder="Parlez de vous..."></textarea>
              
              <button className="btn-sidebar" onClick={saveProfileSettings}>
                <i className="fas fa-save mr-2"></i> Enregistrer
              </button>
            </div>
            
            {/* ====== قسم الروابط الاجتماعية ====== */}
            <div className="sidebar-section">
              <div className="sidebar-title"><i className="fas fa-share-alt"></i> Liens sociaux</div>
              
              <label className="sidebar-label">📘 Facebook</label>
              <input type="text" className="sidebar-input" placeholder="https://facebook.com/..." value={socialLinks.facebook} onChange={(e) => updateSocialLink('facebook', e.target.value)} />
              
              <label className="sidebar-label">📷 Instagram</label>
              <input type="text" className="sidebar-input" placeholder="https://instagram.com/..." value={socialLinks.instagram} onChange={(e) => updateSocialLink('instagram', e.target.value)} />
              
              <label className="sidebar-label">🐦 Twitter</label>
              <input type="text" className="sidebar-input" placeholder="https://twitter.com/..." value={socialLinks.twitter} onChange={(e) => updateSocialLink('twitter', e.target.value)} />
              
              <label className="sidebar-label">🔗 LinkedIn</label>
              <input type="text" className="sidebar-input" placeholder="https://linkedin.com/..." value={socialLinks.linkedin} onChange={(e) => updateSocialLink('linkedin', e.target.value)} />
              
              <label className="sidebar-label">🎵 TikTok</label>
              <input type="text" className="sidebar-input" placeholder="https://tiktok.com/..." value={socialLinks.tiktok} onChange={(e) => updateSocialLink('tiktok', e.target.value)} />
              
              <button className="btn-sidebar" onClick={saveSocialLinks}>
                <i className="fas fa-save mr-2"></i> Enregistrer
              </button>
            </div>
            
            {/* ====== زر تسجيل الخروج ====== */}
            <div className="sidebar-section">
              <button className="btn-sidebar btn-danger-sidebar" onClick={() => setShowLogoutConfirm(true)}>
                <i className="fas fa-sign-out-alt mr-2"></i> Déconnexion
              </button>
            </div>
          </div>
        </>
      )}
      
      {/* ========== مودال عروض العمل (كرت المطعم فقط) ========== */}
      {showJobOffers && (
        <div className="job-offers-modal-overlay" onClick={() => setShowJobOffers(false)}>
          <div className="job-offers-modal-container" onClick={(e) => e.stopPropagation()}>
            <button className="close-offers-btn" onClick={() => setShowJobOffers(false)}>✕</button>
            <h3 className="offers-title">📢 عروض العمل المتاحة</h3>
            
            <div className="offers-list">
              {jobOffers.length === 0 ? (
                <div className="no-offers-message">
                  <div style={{ fontSize: '3rem', marginBottom: '10px' }}>🎉</div>
                  <p>لا توجد عروض عمل حالياً</p>
                </div>
              ) : (
                jobOffers.map((offer) => (
                  <div key={offer.id} className="restaurant-card">
                    <div className="restaurant-name">
                      <span>{offer.icon}</span> {offer.restaurantName}
                    </div>
                    <div className="restaurant-detail">
                      <span>📍</span> {offer.location}
                    </div>
                    <div className="restaurant-detail">
                      <span>💼</span> {offer.position}
                    </div>
                    <div className="restaurant-detail">
                      <span>💰</span> {offer.salary}
                    </div>
                    <div className="restaurant-description">
                      {offer.description}
                    </div>
                    <div className="restaurant-actions">
                      <button 
                        className="accept-btn"
                        onClick={() => handleAcceptOffer(offer.id)}
                      >
                        ✅ قبول
                      </button>
                      <button 
                        className="reject-btn"
                        onClick={() => handleRejectOffer(offer.id)}
                      >
                        ❌ رفض
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}
      
      {/* ========== إشعار ========== */}
      {showNotification && (
        <div className="notification-toast">
          {notificationMessage}
        </div>
      )}
      
      {/* ========== مودال تأكيد تسجيل الخروج ========== */}
      {showLogoutConfirm && (
        <div className="modal-overlay-custom" onClick={() => setShowLogoutConfirm(false)}>
          <div className="modal-content-custom" onClick={(e) => e.stopPropagation()}>
            <div className="text-center">
              <div className="text-5xl mb-3">🚪</div>
              <h3 className="text-xl font-bold text-white mb-3">Déconnexion</h3>
              <p className="text-gray-300 mb-5">Êtes-vous sûr de vouloir vous déconnecter ?</p>
              <div className="confirm-buttons">
                <button className="btn-sidebar" style={{ background: '#22c55e' }} onClick={handleLogout}>
                  <i className="fas fa-check mr-2"></i> Oui
                </button>
                <button className="btn-sidebar btn-danger-sidebar" onClick={() => setShowLogoutConfirm(false)}>
                  <i className="fas fa-times mr-2"></i> Non
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
      
      {/* ========== أيقونات التواصل الاجتماعي ========== */}
      <div style={{ position: 'fixed', bottom: '20px', left: 0, right: 0, zIndex: 50 }}>
        <SocialIcons />
      </div>
    </>
  );
}
